import ollama

response = ollama.embed(
    model="nomic-embed-text:latest",
    input="File: data_preprocessor.py | Type: class | Name: DataPreprocessor\n\nclass DataPreprocessor:\r\n\r\n    def __init__(self, artifacts_setup: ArtifactsSetup):\r\n        logging.debug(\"Initializing data preprocessor\")\r\n        self.preprocessing_pipeline = DataPreprocessingPipelineGenerator().generate_pipeline()\r\n        config = config_loader.load_config()\r\n        self.numerical_columns = config[\"features\"][\"num_cols\"]\r\n        self.categorical_columns = config[\"features\"][\"cat_cols\"]        \r\n        self.drop_unimportant_columns = config[\"features\"][\"drop_cols\"]\r\n\r\n        self.artifacts_setup = artifacts_setup\r\n        self.artifacts_path = self.artifacts_setup.artifact_path\r\n\r\n    def fit_transform(self, X: pd.DataFrame):\r\n        try:\r\n            logging.info(\"Fitting preprocessing pipeline on training data\")\r\n            \r\n            logging.debug(\"Dropping unimportant columns from X\")\r\n            X = X.drop(columns=self.drop_unimportant_columns, errors=\"ignore\")\r\n\r\n            X_transformed = self.preprocessing_pipeline.fit_transform(X)\r\n            X_column_names = (\r\n                self.preprocessing_pipeline\r\n                    .named_steps[\"column_transform\"]\r\n                    .get_feature_names_out()\r\n            )\r\n\r\n            df =  pd.DataFrame(\r\n                X_transformed,\r\n                columns=X_column_names,\r\n                index=X.index\r\n            )\r\n\r\n            logging.debug(f\"Training data shape after transformation: {df.shape}\")\r\n            return df.astype(float)\r\n        except Exception as e:\r\n            logging.error(f\"Error during preprocessing fit_transform: {e}\")\r\n            raise\r\n\r\n    def transform(self, X: pd.DataFrame):\r\n        try:\r\n            logging.debug(\"Dropping unimportant columns from X\")\r\n            X = X.drop(columns=self.drop_unimportant_columns, errors=\"ignore\")\r\n\r\n            X_transformed = self.preprocessing_pipeline.transform(X)\r\n            X_column_names = (\r\n                self.preprocessing_pipeline\r\n                    .named_steps[\"column_transform\"]\r\n                    .get_feature_names_out()\r\n            )\r\n\r\n            df =  pd.DataFrame(\r\n                X_transformed,\r\n                columns=X_column_names,\r\n                index=X.index\r\n            )\r\n\r\n            return df.astype(float)\r\n        except Exception as e:\r\n            logging.error(f\"Error during preprocessing transform: {e}\")\r\n            raise\r\n\r\n    def save_preprocessed_train_data(self, X_train: pd.DataFrame, y_train: pd.Series):\r\n        try:\r\n            logging.info(\"Saving preprocessed train data\")\r\n            train_data = pd.concat([X_train, y_train], axis=1)\r\n            train_data.to_csv(PROCESSED_TRAIN_DATA_PATH, index=False)\r\n        except Exception as e:\r\n            logging.error(f\"Error saving preprocessed train data: {e}\")\r\n            raise\r\n\r\n    def save_preprocessed_test_data(self, X_test: pd.DataFrame, y_test: pd.Series):\r\n        try:\r\n            logging.info(\"Saving preprocessed test data\")\r\n            test_data = pd.concat([X_test, y_test], axis=1)\r\n            test_data.to_csv(PROCESSED_TEST_DATA_PATH, index=False)\r\n        except Exception as e:\r\n            logging.error(f\"Error saving preprocessed test data: {e}\")\r\n            raise\r\n\r\n    def save_preprocessor_pipeline(self):\r\n        try:\r\n            logging.info(\"Saving preprocessor pipeline as artifact\")\r\n            self.artifacts_setup.save_pipeline(self.preprocessing_pipeline, \"preprocessor\")\r\n        \r\n        except Exception as e:\r\n            logging.error(f\"Could not save preprocessor pipeline as artifact: {e}\")",
)
embedding = response["embeddings"][0]

print(embedding)